const { documentToHtmlString } = require("@contentful/rich-text-html-renderer")
const { getGatsbyImageResolver } = require("gatsby-plugin-image/graphql-utils")
const path = require("path")

interface FieldExtensionOptions {
  name: string
}

interface SourceObject {
  internal: {
    type: string
  }
  file?: {
    url: string
  }
  body?: {
    raw: string
  }
  content?: {
    raw: string
  }
}

interface CreateSchemaCustomizationArgs {
  actions: {
    createFieldExtension: (config: any) => void
    createTypes: (types: string) => void
  }
}

exports.createSchemaCustomization = async ({ actions }: CreateSchemaCustomizationArgs) => {
  actions.createFieldExtension({
    name: "blocktype",
    extend(options: FieldExtensionOptions) {
      return {
        resolve(source: SourceObject) {
          return source.internal.type.replace("Contentful", "")
        },
      }
    },
  })

  actions.createFieldExtension({
    name: "imagePassthroughArgs",
    extend(options: FieldExtensionOptions) {
      const { args } = getGatsbyImageResolver()
      return {
        args,
      }
    },
  })

  actions.createFieldExtension({
    name: "imageUrl",
    extend(options: FieldExtensionOptions) {
      const schemaRE = /^\/\//
      const addURLSchema = (str: string): string => {
        if (schemaRE.test(str)) return `https:${str}`
        return str
      }
      return {
        resolve(source: SourceObject) {
          return addURLSchema(source.file!.url)
        },
      }
    },
  })

  actions.createFieldExtension({
    name: "richText",
    extend(options: FieldExtensionOptions) {
      return {
        resolve(source: SourceObject) {
          const body = source.body
          const doc = JSON.parse(body!.raw)
          const html = documentToHtmlString(doc)
          return html
        },
      }
    },
  })

  actions.createFieldExtension({
    name: "richTextContent",
    extend(options: FieldExtensionOptions) {
      return {
        resolve(source: SourceObject) {
          const content = source.content
          if (!content?.raw) return ""
          const doc = JSON.parse(content.raw)
          return documentToHtmlString(doc)
        },
      }
    },
  })

  // abstract interfaces
  actions.createTypes(/* GraphQL */ `
    interface HomepageLink implements Node {
      id: ID!
      href: String
      text: String
    }

    interface HomepageImage implements Node {
      id: ID!
      alt: String
      gatsbyImageData: GatsbyImageData @imagePassthroughArgs
      url: String
    }

    enum SocialService {
      TWITTER
      FACEBOOK
      INSTAGRAM
      YOUTUBE
      LINKEDIN
      GITHUB
      DISCORD
      TWITCH
    }

    interface SocialLink implements Node {
      id: ID!
      username: String!
      service: SocialService!
    }

    interface LayoutFooter implements Node {
      id: ID!
      links: [HomepageLink]
      meta: [HomepageLink]
      socialLinks: [SocialLink]
      copyright: String
    }

    interface Layout implements Node {
      id: ID!
      footer: LayoutFooter
    }

    interface AboutPage implements Node {
      id: ID!
      title: String
      description: String
    }

    interface Page implements Node {
      id: ID!
      slug: String!
      title: String
      description: String
      images: [HomepageImage]
      html: String!
    }
  `)

  // CMS-specific types
  actions.createTypes(/* GraphQL */ `
    type ContentfulHomepageLink implements Node & HomepageLink @dontInfer {
      id: ID!
      href: String
      text: String
    }

    type ContentfulAsset implements Node & HomepageImage {
      id: ID!
      alt: String @proxy(from: "title")
      gatsbyImageData: GatsbyImageData
      url: String @imageUrl
      file: JSON
      title: String
    }

    type ContentfulAboutPage implements Node & AboutPage @dontInfer {
      id: ID!
      title: String
      description: String
    }

    type ContentfulSocialLink implements Node & SocialLink @dontInfer {
      id: ID!
      username: String!
      service: SocialService!
    }

    type ContentfulLayoutFooter implements Node & LayoutFooter @dontInfer {
      id: ID!
      links: [HomepageLink] @link(from: "links___NODE")
      meta: [HomepageLink] @link(from: "meta___NODE")
      socialLinks: [SocialLink] @link(from: "socialLinks___NODE")
      copyright: String
    }

    type ContentfulLayout implements Node & Layout @dontInfer {
      id: ID!
      footer: LayoutFooter @link(from: "footer___NODE")
    }
  `)

  // Page types
  actions.createTypes(/* GraphQL */ `
    type ContentfulPage implements Node & Page {
      id: ID!
      slug: String!
      title: String
      description: String
      images: [HomepageImage] @link(from: "images___NODE")
      html: String! @richTextContent
    }
  `)
}

interface CreatePagesArgs {
  actions: {
    createSlice: (config: any) => void
    createPage: (config: any) => void
  }
  graphql: (query: string) => Promise<any>
}

// helper slice map used on every page that wants footer
const defaultSlicesMap = {
  footer: `footer`,
}

exports.createPages = async ({ actions, graphql }: CreatePagesArgs) => {
  const { createSlice } = actions

  // register slice components globally
  if (typeof createSlice === `function`) {
    createSlice({
      id: "footer",
      component: path.resolve(__dirname, `./src/slices/footer.tsx`),
    })
  }

  // Query all contentfulPoem nodes and create pages
  const result = await graphql(`
    query {
      allContentfulPoem {
        edges {
          node {
            id
            slug
          }
        }
      }
    }
  `)

  if (result.errors) {
    throw result.errors
  }

  const poems = result.data?.allContentfulPoem?.edges || []
  
  poems.forEach(({ node }: { node: { id: string; slug: string } }) => {
    actions.createPage({
      path: `/poems/${node.slug}`,
      component: path.resolve(__dirname, `./src/pages/{contentfulPoem.slug}.tsx`),
      context: {
        slug: node.slug,
        slicesMap: defaultSlicesMap,
      },
    })
  })
}

// inject slicesMap into ALL pages
exports.onCreatePage = ({ page, actions }: any) => {
  const { createPage, deletePage } = actions

  // skip if already has slicesMap
  if (page.context?.slicesMap) {
    return
  }

  deletePage(page)
  createPage({
    ...page,
    context: {
      ...page.context,
      slicesMap: defaultSlicesMap,
    },
  })
}
